```javascript
import { withDb } from "./db.mjs";

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const { rows } = await client.query("SELECT account_id, doc FROM accounts LIMIT 1");
    if (!rows.length) throw new Error("No accounts found");

    const { account_id, doc } = rows[0];
    const requestId = doc.request?.requestId || account_id;
    const nowDate = new Date(now);

    const signals = [];

    const hasRegHold = doc.regulatoryFlags?.some((f) => f.status === "open");
    if (hasRegHold) signals.push("Regulatory hold");

    const hasOverdueInvoice = doc.invoices?.some((inv) => {
      return inv.status !== "paid" && new Date(inv.dueDate) < nowDate && inv.amountCents >= 2500000;
    });
    if (hasOverdueInvoice) signals.push("Overdue invoice");

    const hasDelayedShipment = doc.shipments?.some((s) => {
      return !s.deliveredDate && new Date(s.slaDate) < nowDate;
    });
    if (hasDelayedShipment) signals.push("Delayed shipment");

    const hasEscalatedSupport = doc.supportCases?.some((c) => {
      return c.status === "open" && (c.severity === "high" || c.severity === "critical");
    });
    if (hasEscalatedSupport) signals.push("Escalated support");

    if (doc.usage) {
      if (doc.usage.currentPeriodUnits <= doc.usage.priorPeriodUnits * 0.7) {
        signals.push("Usage decline");
      }
