71	    await client.query("DELETE FROM customer_messages WHERE account_id = $1", [account_id]);
72	    await client.query("DELETE FROM audit_events WHERE account_id = $1", [account_id]);
73	
74	    await client.query(
75	      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
76	      [requestId, account_id, doc.request?.title || "Account Rescue", status, nextStep, riskSummary]
77	    );
78	
79	    if (qualifies) {
80	      for (const owner of owners) {
81	        await client.query(
82	          "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
83	          [requestId, account_id, owner, `${owner} recovery review`, dueAt.toISOString(), "open"]
84	        );
85	      }
86	
87	      const customerMessage =
88	        "Your account has been flagged for priority review by our team. " +
89	        "We have identified several areas that require immediate attention and have mobilized the appropriate teams to address them. " +
90	        "Our dedicated specialists are actively coordinating to resolve these issues and will be reaching out to you directly with an action plan. " +
91	        "We value your partnership and are committed to ensuring your experience meets the highest standards. " +
92	        "Thank you for your continued trust.";
93	      await client.query(
94	        "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
95	        [requestId, account_id, customerMessage]
96	      );
97	    }
98	
99	    const event = qualifies
100	      ? `Escalation workflow initiated: ${riskSummary}`
101	      : "Account reviewed — no escalation required.";
102	    await client.query(
103	      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
104	      [requestId, account_id, event, nowDate.toISOString(), true]
105	    );
106	  });
107	}
108	
109	if (import.meta.url === `file://${process.argv[1]}`) {
110	  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
111	}
